# Longest substring without repeating chars — O(n)
def length_of_longest_substring(s):
    char_idx = {}
    l = res = 0
    for r, c in enumerate(s):
        if c in char_idx and char_idx[c] >= l:
            l = char_idx[c] + 1  # shrink from left
        char_idx[c] = r
        res = max(res, r - l + 1)
    return res

# Fixed window max sum of size k — O(n)
def max_sum_k(nums, k):
    window = sum(nums[:k])
    res = window
    for i in range(k, len(nums)):
        window += nums[i] - nums[i-k]
        res = max(res, window)
    return res

