# Next greater element — O(n) using monotonic stack
def next_greater(nums):
    res = [-1] * len(nums)
    stack = []  # indices, monotonic decreasing values
    for i, n in enumerate(nums):
        while stack and nums[stack[-1]] < n:
            res[stack.pop()] = n  # n is the next greater for popped index
        stack.append(i)
    return res

# Min stack O(1) getMin
class MinStack:
    def __init__(self):
        self.stack = []
        self.min_stack = []
    def push(self, val):
        self.stack.append(val)
        self.min_stack.append(min(val, self.min_stack[-1] if self.min_stack else val))
    def pop(self):
        self.stack.pop(); self.min_stack.pop()
    def getMin(self):
        return self.min_stack[-1]

