# Rotate Matrix 90° clockwise — O(n²)
def rotate(matrix):
    # Step 1: Transpose (swap [i][j] and [j][i])
    n = len(matrix)
    for i in range(n):
        for j in range(i+1, n):
            matrix[i][j], matrix[j][i] = matrix[j][i], matrix[i][j]
    # Step 2: Reverse each row
    for row in matrix:
        row.reverse()

# Count Primes — Sieve of Eratosthenes O(n log log n)
def count_primes(n):
    sieve = [True] * n
    sieve[0] = sieve[1] = False
    for i in range(2, int(n**0.5) + 1):
        if sieve[i]:
            for j in range(i*i, n, i):
                sieve[j] = False
    return sum(sieve)

# Fast Power — O(log n)
def my_pow(x, n):
    if n < 0: x, n = 1/x, -n
    result = 1
    while n:
        if n % 2: result *= x
        x *= x
        n //= 2
    return result

